#include<bits/stdc++.h>
using namespace std;
int n,m,x,y,a[505][505],s[505][505],l,r,ans;
bool check(int k){
	int now=0,cnt=0;
	for(int i=1;i<=n;i++){
		int ct=0,sum=0;
		for(int j=1;j<=m;j++){
			if(sum+s[i][j]-s[i][j-1]-s[now][j]+s[now][j-1]<k)
				sum+=s[i][j]-s[i][j-1]-s[now][j]+s[now][j-1];
			else sum=0,ct++;
		}
		if(ct>=y)cnt++,now=i;
	}
	return cnt>=x;
}
int main(){
	cin>>n>>m>>x>>y;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)cin>>a[i][j];
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			s[i][j]=s[i-1][j]+s[i][j-1]-s[i-1][j-1]+a[i][j];
	l=0,r=s[n][m];
	while(l<=r){
		int mid=(l+r)/2;
		if(check(mid))ans=mid,l=mid+1;
		else r=mid-1;
	}
	cout<<ans;
	return 0;
}
